{"type": "email", "id": "email_003", "subject": "Customer Satisfaction Survey Results Q3", "from": "linda.chen@leesmarket.com", "from_name": "Linda Chen", "to": ["grace.kim@leesmarket.com", "michael.lee@leesmarket.com", "john.murphy@leesmarket.com", "hannah.jones@leesmarket.com", "sam.walker@leesmarket.com"], "cc": [], "date": "2022-10-18 10:30:00", "body": "Hi Team,

